/* BTKbd — keyboard key badge.
   Figma: D-Kbd node 2637:2613 (web only — no Flutter equivalent).
   Shared between @btech/ui-vue and @btech/ui-react — keep these files identical. */

.bt-kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 16px;
  min-width: 16px;
  border-radius: var(--radius-xs);
  background: var(--bg-subtle);
  padding: 0 var(--space-2xs);
  pointer-events: none;
  user-select: none;
  vertical-align: middle;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-2xs);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-secondary);
  white-space: nowrap;
}

/* Icon variant — equal padding on all sides */
.bt-kbd--icon {
  padding: var(--space-2xs);
}

/* Dark variant — component-specific bg hardcoded (no semantic light-mode token) */
.bt-kbd--dark {
  /* Raw hex allowed (CLAUDE.md §2) — neutral/700, no semantic token maps to this in light mode */
  background: #3c4450;
  color: var(--text-tertiary);
}

/* Group — horizontal row of kbd badges */
.bt-kbd-group {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2xs);
}

/**
 * BTKbd — keyboard key badge.
 *
 * @example
 * ```tsx
 * <BTKbd>⌘</BTKbd>
 * <BTKbd dark>K</BTKbd>
 * <BTKbdGroup>
 *   <BTKbd>Ctrl</BTKbd>
 *   <BTKbd>K</BTKbd>
 * </BTKbdGroup>
 * ```
 */
import './BTKbd.css';
import type { BTKbdProps } from './BTKbd.types';

export function BTKbd({
  variant = 'text',
  dark = false,
  className,
  children,
  ...props
}: BTKbdProps) {
  const cls = [
    'bt-kbd',
    variant === 'icon' && 'bt-kbd--icon',
    dark && 'bt-kbd--dark',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <kbd data-slot="kbd" className={cls} {...props}>
      {children}
    </kbd>
  );
}

BTKbd.displayName = 'BTKbd';

import type { ComponentProps } from 'react';

export type BTKbdVariant = 'text' | 'icon';

export interface BTKbdProps extends ComponentProps<'kbd'> {
  variant?: BTKbdVariant;
  dark?: boolean;
}

export interface BTKbdGroupProps extends ComponentProps<'span'> {
  // layout-only wrapper — inherits all span props
}

/**
 * BTKbdGroup — horizontal row of BTKbd badges.
 *
 * @example
 * ```tsx
 * <BTKbdGroup>
 *   <BTKbd>Ctrl</BTKbd>
 *   <BTKbd>Shift</BTKbd>
 *   <BTKbd>K</BTKbd>
 * </BTKbdGroup>
 * ```
 */
import './BTKbd.css';
import type { BTKbdGroupProps } from './BTKbd.types';

export function BTKbdGroup({ className, children, ...props }: BTKbdGroupProps) {
  const cls = ['bt-kbd-group', className].filter(Boolean).join(' ');

  return (
    <span data-slot="kbd-group" className={cls} {...props}>
      {children}
    </span>
  );
}

BTKbdGroup.displayName = 'BTKbdGroup';
